content:
Use esta base, sem aplicar nada ainda, para montar o microsserviço com Node.js, Express 5 e TypeScript.

```json
{
  "name": "plus-ms-report",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "main": "dist/server.js",
  "scripts": {
    "dev": "nodemon --watch src --ext ts --exec ts-node src/server.ts",
    "build": "tsc -p tsconfig.json",
    "start": "node dist/server.js",
    "lint": "eslint .",
    "test": "jest",
    "test:unit": "jest --selectProjects unit",
    "test:functional": "jest --selectProjects functional",
    "test:coverage": "jest --coverage --selectProjects coverage"
  },
  "dependencies": {
    "cors": "^2.8.5",
    "express": "^5.0.0",
    "jsonwebtoken": "^9.0.2",
    "json2csv": "^6.0.0-alpha.2",
    "pdfkit": "^0.17.1",
    "swagger-ui-express": "^5.0.1"
  },
  "devDependencies": {
    "@types/cors": "^2.8.17",
    "@types/express": "^5.0.0",
    "@types/jest": "^29.5.14",
    "@types/jsonwebtoken": "^9.0.10",
    "@types/node": "^22.15.0",
    "@types/supertest": "^6.0.3",
    "eslint": "^9.0.0",
    "eslint-config-prettier": "^10.0.1",
    "eslint-plugin-import": "^2.31.0",
    "eslint-plugin-jest": "^28.11.0",
    "eslint-plugin-simple-import-sort": "^12.1.1",
    "jest": "^29.7.0",
    "nodemon": "^3.1.10",
    "supertest": "^7.1.0",
    "ts-jest": "^29.3.2",
    "ts-node": "^10.9.2",
    "typescript": "^5.8.3"
  }
}
```

Para o TypeScript, use um `tsconfig` voltado para Node moderno, com saída em `dist`, suporte a imports ESM e arquivos de teste separados:

```json
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "NodeNext",
    "moduleResolution": "NodeNext",
    "lib": ["ES2022"],
    "outDir": "./dist",
    "rootDir": "./src",
    "strict": true,
    "esModuleInterop": true,
    "forceConsistentCasingInFileNames": true,
    "skipLibCheck": true,
    "resolveJsonModule": true,
    "sourceMap": true,
    "types": ["node", "jest"]
  },
  "include": ["src/**/*.ts", "tests/**/*.ts"],
  "exclude": ["dist", "node_modules"]
}
```

Para o ESLint em flat config, o arquivo `eslint.config.mts` pode seguir esta linha:

```ts
import js from '@eslint/js';
import tseslint from 'typescript-eslint';
import jestPlugin from 'eslint-plugin-jest';
import importSort from 'eslint-plugin-simple-import-sort';
import prettier from 'eslint-config-prettier';

export default [
  {
    ignores: ['dist/**', 'coverage/**', 'node_modules/**']
  },
  js.configs.recommended,
  ...tseslint.configs.recommended,
  {
    files: ['**/*.ts'],
    languageOptions: {
      parserOptions: {
        project: './tsconfig.json'
      }
    },
    plugins: {
      jest: jestPlugin,
      'simple-import-sort': importSort
    },
    rules: {
      'simple-import-sort/imports': 'error',
      'simple-import-sort/exports': 'error',
      '@typescript-eslint/no-unused-vars': ['error', { argsIgnorePattern: '^_' }],
      'jest/no-disabled-tests': 'warn'
    }
  },
  prettier
];
```

Para o Jest, eu sugiro um único arquivo de configuração com três projetos: unitário, funcional e coverage. Assim você separa a intenção de cada suíte sem duplicar muita configuração.

```ts
import type { Config } from 'jest';

const base: Config = {
  preset: 'ts-jest',
  testEnvironment: 'node',
  clearMocks: true,
  collectCoverageFrom: ['src/**/*.ts', '!src/**/*.d.ts'],
  coverageDirectory: 'coverage'
};

const config: Config = {
  projects: [
    {
      ...base,
      displayName: 'unit',
      testMatch: ['<rootDir>/tests/unit/**/*.test.ts']
    },
    {
      ...base,
      displayName: 'functional',
      testMatch: ['<rootDir>/tests/functional/**/*.test.ts']
    },
    {
      ...base,
      displayName: 'coverage',
      testMatch: ['<rootDir>/tests/**/*.test.ts'],
      collectCoverage: true
    }
  ]
};

export default config;
```

